const tallyBody = $json.body || {};
const isTally = !!tallyBody.data?.fields;

function getField(label) {
  if (!isTally) return null;
  return tallyBody.data.fields.find(x => x.label && x.label.toLowerCase().includes(label.toLowerCase()));
}
function getValue(label, directKey) {
  const f = getField(label);
  if (f) {
    if (f.type === 'FILE_UPLOAD' && Array.isArray(f.value)) return f.value.map(v => v.url);
    if (Array.isArray(f.value)) return f.value;
    return f.value || '';
  }
  return tallyBody[directKey] !== undefined ? tallyBody[directKey] : '';
}

const imobiliaria = getValue('Nome da Imobiliária', 'imobiliaria') || 'Imobiliária Prisma';
const logoArr = getValue('Logótipo da Imobiliária', 'logo');
const logoUrl = Array.isArray(logoArr) ? (logoArr[0] || '') : (logoArr || '');
const titulo = getValue('Título do Imóvel', 'titulo') || 'Imóvel Exclusivo';
const preco = getValue('Preço', 'preco') || 'Sob consulta';
const tipologia = getValue('Tipologia', 'tipologia') || '';
const area = getValue('Área', 'area') || '';
const quartos = getValue('Quartos', 'quartos') || '';
const wc = getValue('WC', 'wc') || '';
const localizacao = getValue('Localização', 'localizacao') || '';
const fotosArr = getValue('Fotos do Imóvel', 'fotos');
const fotos = Array.isArray(fotosArr) ? fotosArr : (fotosArr ? [fotosArr] : []);
const videoUrl = getValue('Link do Vídeo', 'video_url') || '';
const destaque1 = getValue('Destaque 1', 'destaque1') || '';
const destaque2 = getValue('Destaque 2', 'destaque2') || '';
const destaque3 = getValue('Destaque 3', 'destaque3') || '';
const extrasArr = getValue('Extras', 'extras');
const extras = Array.isArray(extrasArr) ? extrasArr : (extrasArr ? [extrasArr] : []);
const ano = getValue('Ano de Construção', 'ano') || '';
const corretorNome = getValue('Nome do Corretor', 'corretor_nome') || imobiliaria;
const corretorWhatsapp = getValue('WhatsApp do Corretor', 'corretor_whatsapp') || '+351900000000';
const corretorEmail = getValue('Email do Corretor', 'corretor_email') || '';
const nif = getValue('NIF', 'nif') || '';

const imovel = {
  imobiliaria, logo: logoUrl, titulo, preco, tipologia, area, quartos, wc, localizacao,
  fotos, video_url: videoUrl,
  destaques_unicos: [destaque1, destaque2, destaque3].filter(Boolean),
  extras, ano, corretor: { nome: corretorNome, whatsapp: corretorWhatsapp, email: corretorEmail }, nif
};

const FONT_POOL = 'Cormorant Garamond + Inter; Playfair Display + Source Sans 3; Fraunces + Work Sans; Libre Caslon + Karla; Marcellus + Mulish';
const BLACKLIST = 'imóvel de sonho, localização privilegiada, acabamentos de luxo, oportunidade única, excelente investimento, charme, requinte, sucesso, excelência';

let logoStatus = 'ausente';
let logoInlinePart = null;
let logoBase64 = '';
let logoMime = '';
if (logoUrl) {
  try {
    const res = await this.helpers.httpRequest({ url: logoUrl, encoding: 'arraybuffer' });
    logoBase64 = Buffer.from(res).toString('base64');
    logoMime = logoUrl.toLowerCase().endsWith('.png') ? 'image/png'
      : logoUrl.toLowerCase().endsWith('.svg') ? 'image/svg+xml'
      : logoUrl.toLowerCase().endsWith('.webp') ? 'image/webp' : 'image/jpeg';
    logoInlinePart = { inlineData: { mimeType: logoMime, data: logoBase64 } };
    logoStatus = 'presente, imagem fornecida';
  } catch (e) {
    logoStatus = 'ausente (falha ao descarregar)';
  }
}

const promptText = `Atuas como Diretor Criativo de uma agência especializada em imobiliário de luxo em Portugal.
Vais criar a identidade e todo o conteúdo de uma landing page para UM imóvel específico.

DADOS DO IMÓVEL: ${JSON.stringify(imovel)}
LOGO: ${logoStatus}

REGRAS:
1. Preenche TODOS os campos do schema. Nenhum vazio.
2. Escolhe o arquétipo: "cinematic" se há fotos espetaculares e/ou vídeo (hero full-screen);
   "editorial" se o imóvel tem história/carácter (composição assimétrica tipo revista de arquitetura);
   "gallery_first" se há muitos espaços/divisões distintos (a grelha de fotos é o hero).
3. Paleta: se houver logo, deriva da marca; se não houver, escolhe pelo carácter do imóvel
   (praia→areias/azuis profundos; urbano→grafite/dourado; rural→terracota/oliva).
   PROIBIDO: paletas default de startup (roxo/gradiente azul-rosa).
4. Fontes: escolhe UM par do pool: ${FONT_POOL}.
5. Copy: português europeu, sóbrio, sensorial. O headline TEM de usar um dos destaques únicos
   fornecidos em destaques_unicos. PROIBIDO usar estas expressões ou emojis: ${BLACKLIST}.
6. ficha_tecnica: converte tipologia/área/quartos/wc/extras/preço em pares label-valor.
7. Justifica as tuas escolhas na direction_sheet (2-3 frases cada). Em detalhe_unico_usado,
   indica qual dos destaques_unicos usaste no headline.`;

const parts = [{ text: promptText }];
if (logoInlinePart) parts.push(logoInlinePart);

const responseSchema = {
  type: 'OBJECT',
  required: ['direction_sheet','identity','hero','imovel','galeria','localizacao','agendamento','seo'],
  properties: {
    direction_sheet: { type:'OBJECT', required:['arquetipo','justificacao_arquetipo','justificacao_paleta','detalhe_unico_usado'],
      properties: {
        arquetipo: { type:'STRING', enum:['cinematic','editorial','gallery_first'] },
        justificacao_arquetipo: { type:'STRING' },
        justificacao_paleta: { type:'STRING' },
        detalhe_unico_usado: { type:'STRING' }
      }},
    identity: { type:'OBJECT', required:['paleta','fontes'],
      properties: {
        paleta: { type:'OBJECT', required:['bg','surface','ink','accent','accent_soft'],
          properties: { bg:{type:'STRING'}, surface:{type:'STRING'}, ink:{type:'STRING'}, accent:{type:'STRING'}, accent_soft:{type:'STRING'} } },
        fontes: { type:'OBJECT', required:['display','body'],
          properties: { display:{type:'STRING'}, body:{type:'STRING'} } }
      }},
    hero: { type:'OBJECT', required:['eyebrow','headline','subheadline','cta_label'],
      properties: { eyebrow:{type:'STRING'}, headline:{type:'STRING'}, subheadline:{type:'STRING'}, cta_label:{type:'STRING'} } },
    imovel: { type:'OBJECT', required:['descricao_lifestyle','destaques','ficha_tecnica'],
      properties: {
        descricao_lifestyle: { type:'STRING' },
        destaques: { type:'ARRAY', minItems:3, maxItems:5, items: { type:'OBJECT', required:['titulo','descricao'], properties: { titulo:{type:'STRING'}, descricao:{type:'STRING'} } } },
        ficha_tecnica: { type:'ARRAY', items: { type:'OBJECT', required:['label','valor'], properties: { label:{type:'STRING'}, valor:{type:'STRING'} } } }
      }},
    galeria: { type:'OBJECT', required:['headline'], properties: { headline:{type:'STRING'}, legendas:{type:'ARRAY', items:{type:'STRING'}} } },
    localizacao: { type:'OBJECT', required:['headline','descricao_zona'], properties: { headline:{type:'STRING'}, descricao_zona:{type:'STRING'} } },
    agendamento: { type:'OBJECT', required:['headline','subtext','button_label'], properties: { headline:{type:'STRING'}, subtext:{type:'STRING'}, button_label:{type:'STRING'} } },
    seo: { type:'OBJECT', required:['title','description'], properties: { title:{type:'STRING'}, description:{type:'STRING'} } }
  }
};

const geminiRequest = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.85, maxOutputTokens: 8192, responseMimeType: 'application/json', responseSchema }
};

return [{ json: { geminiRequest, imovel_raw: imovel, logo_base64: logoBase64, logo_mime: logoMime } }];

function escapeHtml(unsafe) {
  if (unsafe === undefined || unsafe === null) return '';
  return String(unsafe).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}
function escapeAttr(unsafe) {
  if (unsafe === undefined || unsafe === null) return '';
  return String(unsafe).replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}
function safeUrl(unsafeUrl) {
  if (!unsafeUrl) return '';
  const u = String(unsafeUrl).trim();
  if (u.startsWith('http://') || u.startsWith('https://')) return escapeAttr(u);
  return '';
}
function toEmbedUrl(url) {
  if (!url) return '';
  const u = String(url).trim();
  let m = u.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{6,})/);
  if (m) return 'https://www.youtube.com/embed/' + m[1];
  m = u.match(/vimeo\.com\/(?:video\/)?(\d+)/);
  if (m) return 'https://player.vimeo.com/video/' + m[1];
  return '';
}
function toNumericPrice(str) {
  if (!str) return '';
  const digits = String(str).replace(/[^\d]/g, '');
  return digits || '';
}
function slugify(str) {
  return String(str || 'imovel').toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').substring(0, 60) || 'imovel';
}
function isLowResImage(base64, mime) {
  try {
    const buf = Buffer.from(base64, 'base64');
    if (mime === 'image/png' && buf.length > 24 && buf.readUInt32BE(0) === 0x89504e47) {
      const width = buf.readUInt32BE(16);
      const height = buf.readUInt32BE(20);
      return width < 200 || height < 200;
    }
    if (mime === 'image/jpeg') {
      let i = 2;
      while (i < buf.length - 9) {
        if (buf[i] !== 0xFF) { i++; continue; }
        const marker = buf[i + 1];
        if (marker >= 0xC0 && marker <= 0xC3) {
          const height = buf.readUInt16BE(i + 5);
          const width = buf.readUInt16BE(i + 7);
          return width < 200 || height < 200;
        }
        const segLen = buf.readUInt16BE(i + 2);
        i += 2 + segLen;
      }
    }
  } catch (e) { /* formato não reconhecido (svg/webp) — não classifica como fraca */ }
  return false;
}
function renderLoop(html, key, items) {
  const escKey = key.replace('.', '\\.');
  const re = new RegExp('\\{\\{#' + escKey + '\\}\\}([\\s\\S]*?)\\{\\{\\/' + escKey + '\\}\\}');
  const m = html.match(re);
  if (!m) return html;
  const block = m[1];
  const rendered = (items || []).map(item => {
    let s = block;
    for (const k in item) {
      s = s.split('{{' + k + '}}').join(item[k]);
    }
    return s;
  }).join('');
  return html.replace(re, rendered);
}
function renderIf(html, key, condition) {
  const re = new RegExp('<!--IF:' + key + '-->([\\s\\S]*?)<!--/IF:' + key + '-->', 'g');
  return html.replace(re, condition ? '$1' : '');
}
function stripHeroArchetypes(html, chosen) {
  const all = ['cinematic', 'editorial', 'gallery_first'];
  for (const name of all) {
    if (name === chosen) continue;
    const re = new RegExp('<section class="hero-block[^"]*"[^>]*data-archetype-hero="' + name + '"[\\s\\S]*?<\\/section>');
    html = html.replace(re, '');
  }
  return html;
}

// 1. Parse Gemini response — falha explícita, sem fallback genérico
let geminiText = '';
try {
  const cands = $items('Google Gemini v2')[0].json.candidates;
  const parts = cands[0].content.parts;
  geminiText = parts[parts.length - 1].text || '';
} catch (e) {
  throw new Error('COMPILADOR: resposta do Gemini sem candidates/parts válidos. Execução falhada, nada publicado.');
}

let g;
try {
  const cleaned = geminiText.replace(/```json/g, '').replace(/```/g, '').trim();
  g = JSON.parse(cleaned);
} catch (e) {
  throw new Error('COMPILADOR: JSON do Gemini inválido, execução falhada. Raw (300 chars): ' + geminiText.substring(0, 300));
}
const REQUIRED_TOP = ['direction_sheet','identity','hero','imovel','galeria','localizacao','agendamento','seo'];
for (const k of REQUIRED_TOP) {
  if (!g[k]) throw new Error('COMPILADOR: campo obrigatório "' + k + '" ausente na resposta do Gemini. Execução falhada.');
}

// 2. Dados brutos do Tally
const src = $items('Prepara Payload Gemini')[0].json;
const imovelRaw = src.imovel_raw || {};
const logoBase64 = src.logo_base64 || '';
const logoMime = src.logo_mime || '';

// Meta (novos nesta geração)
const landingId = Date.now().toString(36) + Math.random().toString(36).substring(2, 8) + Math.random().toString(36).substring(2, 8);
const expiresAt = new Date(Date.now() + 24 * 3600 * 1000).toISOString();
const estado = 'preview';
const dominio = null;

// 3. Template
const htmlBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
let html = htmlBuffer.toString('utf8');

// 4. Logo — os 3 cenários
const hasLogo = !!(imovelRaw.logo && logoBase64);
const logoFraca = hasLogo && isLowResImage(logoBase64, logoMime);
const showLogoHeader = hasLogo && !logoFraca;
const showWordmark = !hasLogo || logoFraca;

// 5. Vídeo
const embedUrl = toEmbedUrl(imovelRaw.video_url);
const hasVideo = !!embedUrl;

// 6. Meta / preview
const corretorWaDigits = String(imovelRaw.corretor?.whatsapp || '').replace(/\D/g, '');
const corretorWaLink = 'https://wa.me/' + corretorWaDigits;
const paymentLink = 'https://wa.me/' + corretorWaDigits + '?text=' + encodeURIComponent('Quero publicar a minha landing "' + imovelRaw.titulo + '"');
const agendamentoEndpoint = 'http://161.35.19.139/webhook/agendar-visita';
const slug = slugify(imovelRaw.titulo);
const fileNameBase = slug + '-' + landingId;
const canonical = 'http://161.35.19.139/' + fileNameBase + '.html';

// 7. Loops
const destaques = (g.imovel.destaques || []).map(d => ({ titulo: escapeHtml(d.titulo), descricao: escapeHtml(d.descricao) }));
const fichaTecnica = (g.imovel.ficha_tecnica || []).map(f => ({ label: escapeHtml(f.label), valor: escapeHtml(f.valor) }));
const fotos = (imovelRaw.fotos || []).slice(0, 15);
const legendas = g.galeria.legendas || [];
const galeriaFotos = fotos.map((url, i) => ({
  src: safeUrl(url),
  alt: escapeAttr(imovelRaw.titulo + ' — foto ' + (i + 1)),
  legenda: escapeHtml(legendas[i] || '')
}));

html = renderLoop(html, 'imovel.ficha_tecnica', fichaTecnica);
html = renderLoop(html, 'imovel.destaques', destaques);
html = renderLoop(html, 'galeria.fotos', galeriaFotos);

// 8. Condicionais
html = renderIf(html, 'preview_banner', estado === 'preview');
html = renderIf(html, 'logo', showLogoHeader);
html = renderIf(html, 'wordmark', showWordmark);
html = renderIf(html, 'video', hasVideo);
if (!hasVideo) {
  html = html.replace(/<div class="mb-10 aspect-video reveal">[\s\S]*?<\/div>\s*(?=<div class="grid)/, '');
}

// 9. Arquétipo — remove os 2 heróis não escolhidos
html = stripHeroArchetypes(html, g.direction_sheet.arquetipo);

// 10. Tokens simples
const map = {
  'seo.title': escapeHtml(g.seo.title),
  'seo.description': escapeHtml(g.seo.description),
  'seo.canonical': canonical,
  'seo.og_image': safeUrl(fotos[0] || ''),
  'identity.fonts_url': (() => {
    const pair = g.identity.fontes;
    const fam = (name) => encodeURIComponent(name).replace(/%20/g, '+');
    return `https://fonts.googleapis.com/css2?family=${fam(pair.display)}:wght@400;600;700&family=${fam(pair.body)}:wght@400;500;600&display=swap`;
  })(),
  'identity.bg': escapeAttr(g.identity.paleta.bg),
  'identity.surface': escapeAttr(g.identity.paleta.surface),
  'identity.ink': escapeAttr(g.identity.paleta.ink),
  'identity.accent': escapeAttr(g.identity.paleta.accent),
  'identity.accent_soft': escapeAttr(g.identity.paleta.accent_soft),
  'identity.font_display': escapeAttr(g.identity.fontes.display),
  'identity.font_body': escapeAttr(g.identity.fontes.body),
  'identity.arquetipo': g.direction_sheet.arquetipo,
  'brand.favicon': safeUrl(imovelRaw.logo) || safeUrl(fotos[0] || ''),
  'brand.name': escapeHtml(imovelRaw.imobiliaria),
  'brand.logo': safeUrl(imovelRaw.logo),
  'brand.privacy_url': '/privacidade',
  'imovel.titulo': escapeHtml(imovelRaw.titulo),
  'imovel.morada': escapeHtml(imovelRaw.localizacao),
  'imovel.quartos': escapeHtml(imovelRaw.quartos),
  'imovel.area': escapeHtml(imovelRaw.area),
  'imovel.preco_valor': toNumericPrice(imovelRaw.preco),
  'imovel.foto_hero': safeUrl(fotos[0] || ''),
  'imovel.foto_1': safeUrl(fotos[0] || fotos[fotos.length - 1] || ''),
  'imovel.foto_2': safeUrl(fotos[1] || fotos[0] || ''),
  'imovel.foto_3': safeUrl(fotos[2] || fotos[0] || ''),
  'imovel.foto_4': safeUrl(fotos[3] || fotos[0] || ''),
  'imovel.video_embed_url': embedUrl,
  'imovel.descricao_lifestyle': escapeHtml(g.imovel.descricao_lifestyle),
  'hero.eyebrow': escapeHtml(g.hero.eyebrow),
  'hero.headline': escapeHtml(g.hero.headline),
  'hero.subheadline': escapeHtml(g.hero.subheadline),
  'hero.cta_label': escapeHtml(g.hero.cta_label),
  'galeria.headline': escapeHtml(g.galeria.headline),
  'localizacao.headline': escapeHtml(g.localizacao.headline),
  'localizacao.descricao_zona': escapeHtml(g.localizacao.descricao_zona),
  'localizacao.mapa_embed_url': 'https://www.google.com/maps?q=' + encodeURIComponent(imovelRaw.localizacao || '') + '&output=embed',
  'agendamento.headline': escapeHtml(g.agendamento.headline),
  'agendamento.subtext': escapeHtml(g.agendamento.subtext),
  'agendamento.button_label': escapeHtml(g.agendamento.button_label),
  'meta.agendamento_endpoint': agendamentoEndpoint,
  'meta.landing_id': landingId,
  'corretor.nome': escapeHtml(imovelRaw.corretor?.nome),
  'corretor.whatsapp_link': corretorWaLink,
  'corretor.whatsapp_display': escapeHtml(imovelRaw.corretor?.whatsapp),
  'corretor.email': escapeAttr(imovelRaw.corretor?.email),
  'preview.expires_at': expiresAt,
  'preview.payment_link': paymentLink
};
for (const k in map) {
  html = html.split('{{' + k + '}}').join(map[k] ?? '');
}

// 11. SWEEP FINAL — falha a execução se sobrar QUALQUER placeholder
const leftoverTokens = html.match(/\{\{[^}]*\}\}/g) || [];
const leftoverIfs = html.match(/<!--\/?IF:[a-z_]+-->/g) || [];
if (leftoverTokens.length || leftoverIfs.length) {
  throw new Error('SWEEP FALHOU — placeholders por resolver, execução falhada, nada publicado: ' +
    JSON.stringify(leftoverTokens.concat(leftoverIfs)));
}
const heroBlocksLeft = (html.match(/<section class="hero-block/g) || []).length;
const h1Count = (html.match(/<h1[ >]/g) || []).length;
if (heroBlocksLeft !== 1 || h1Count !== 1) {
  throw new Error('SWEEP FALHOU — arquétipo não isolado corretamente (hero-blocks=' + heroBlocksLeft + ', h1=' + h1Count + '), execução falhada, nada publicado.');
}

const fileName = fileNameBase + '.html';
const stateFileName = fileNameBase + '.state.json';
const stateJson = {
  landing_id: landingId,
  cliente: { imobiliaria: imovelRaw.imobiliaria, corretor: imovelRaw.corretor, nif: imovelRaw.nif },
  imovel: imovelRaw,
  gemini_output: g,
  estado: estado,
  expires_at: expiresAt,
  dominio: dominio,
  url: canonical,
  criado: new Date().toISOString()
};
$input.item.binary.data = await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), fileName, 'text/html');
$input.item.binary.state = await this.helpers.prepareBinaryData(Buffer.from(JSON.stringify(stateJson, null, 2), 'utf8'), stateFileName, 'application/json');
$input.item.json.fileName = fileName;
$input.item.json.stateFileName = stateFileName;
$input.item.json.landingId = landingId;
$input.item.json.arquetipo = g.direction_sheet.arquetipo;
$input.item.json.canonical = canonical;
$input.item.json.stateJson = stateJson;

return $input.item;
